import{_ as i,o as e,c as a,ao as t}from"./chunks/framework.CxQyWp31.js";const u=JSON.parse('{"title":"Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"concepts.md","filePath":"concepts.md","lastUpdated":null}'),n={name:"concepts.md"};function o(l,s,p,r,h,d){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="Concepts" tabindex="-1">Concepts <a class="header-anchor" href="#Concepts" aria-label="Permalink to &quot;Concepts {#Concepts}&quot;">​</a></h1><p>This page explains the core design decisions and type hierarchy behind WhatsThePoint.jl.</p><h2 id="Type-Hierarchy" tabindex="-1">Type Hierarchy <a class="header-anchor" href="#Type-Hierarchy" aria-label="Permalink to &quot;Type Hierarchy {#Type-Hierarchy}&quot;">​</a></h2><p>WhatsThePoint builds point clouds through composition:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PointSurface     — Points with normals and areas (one contiguous surface)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>PointBoundary    — Named collection of surfaces forming a closed boundary</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>PointCloud       — Boundary + volume points + optional topology</span></span></code></pre></div><p>All geometric types inherit from <code>Domain{M,C}</code> where <code>M&lt;:Manifold</code> describes the geometric space (currently Euclidean: <code>𝔼{2}</code> or <code>𝔼{3}</code>) and <code>C&lt;:CRS</code> is the coordinate reference system (Cartesian, Cylindrical, Polar, etc.). This parameterization comes from <a href="https://github.com/JuliaGeometry/Meshes.jl" target="_blank" rel="noreferrer">Meshes.jl</a> and enables type stability and proper dispatch.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># A 3D point cloud in Cartesian coordinates on a Euclidean manifold;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># the third parameter is the topology type (NoTopology until set_topology):</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PointCloud{𝔼{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}, Cartesian3D, NoTopology}</span></span></code></pre></div><h2 id="Surface-Elements" tabindex="-1">Surface Elements <a class="header-anchor" href="#Surface-Elements" aria-label="Permalink to &quot;Surface Elements {#Surface-Elements}&quot;">​</a></h2><p>Each boundary point is stored as a <a href="/WhatsThePoint.jl/previews/PR106/api#WhatsThePoint.SurfaceElement"><code>SurfaceElement</code></a> containing:</p><ul><li><p><strong>point</strong> — The geometric position (a face center of the imported mesh — or a Poisson-disk sample when built with <code>PointBoundary(mesh, spacing)</code>)</p></li><li><p><strong>normal</strong> — Outward-pointing unit normal vector</p></li><li><p><strong>area</strong> — Associated surface area</p></li></ul><p>A <a href="/WhatsThePoint.jl/previews/PR106/api#WhatsThePoint.PointSurface"><code>PointSurface</code></a> stores its elements as a <code>StructArray{SurfaceElement}</code>, giving column-oriented memory layout. This means iterating over all normals reads contiguous memory rather than striding through interleaved fields — a significant cache performance advantage when processing thousands of surface elements.</p><h2 id="Immutability-and-Functional-API" tabindex="-1">Immutability and Functional API <a class="header-anchor" href="#Immutability-and-Functional-API" aria-label="Permalink to &quot;Immutability and Functional API {#Immutability-and-Functional-API}&quot;">​</a></h2><p>Most types in WhatsThePoint are <strong>immutable</strong>. Operations return new objects rather than mutating in place:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># set_topology returns a new cloud — the original is unchanged</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cloud2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> set_topology</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cloud, KNNTopology, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># repel returns a new cloud (with NoTopology, since points moved)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cloud3 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> repel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cloud2, spacing)</span></span></code></pre></div><p>This design ensures compatibility with automatic differentiation frameworks and prevents stale state — if points move, the old topology object simply isn&#39;t used.</p><p><strong>Exceptions — mutating operations (indicated by <code>!</code> suffix):</strong></p><ul><li><p><code>split_surface!</code> and <code>combine_surfaces!</code> mutate a <code>PointBoundary</code>&#39;s internal surface dictionary. These reorganize existing surfaces without changing any point data.</p></li><li><p><code>rebuild_topology!</code> recomputes connectivity data in place for mutable topology types (<code>KNNTopology</code>, <code>RadiusTopology</code>), avoiding reallocation when only the spatial index needs refreshing.</p></li><li><p><code>orient_normals!</code> and <code>update_normals!</code> mutate normal vectors in place for efficiency, since normal arrays can be large and reorientation is a pure numerical update.</p></li></ul><p>The pattern is: <strong>geometry creation and transformation</strong> (new point data) uses functional style; <strong>metadata reorganization and derived-quantity recomputation</strong> (normals, topology, surface labels) mutates in-place.</p><h2 id="Topology" tabindex="-1">Topology <a class="header-anchor" href="#Topology" aria-label="Permalink to &quot;Topology {#Topology}&quot;">​</a></h2><p>Topology represents point connectivity — the neighbor stencils used by meshless solvers.</p><p><strong>Type hierarchy:</strong></p><ul><li><p><a href="/WhatsThePoint.jl/previews/PR106/api#WhatsThePoint.AbstractTopology"><code>AbstractTopology</code></a> — Abstract base with storage type parameter</p></li><li><p><a href="/WhatsThePoint.jl/previews/PR106/api#WhatsThePoint.NoTopology"><code>NoTopology</code></a> — Singleton default (no connectivity computed)</p></li><li><p><a href="/WhatsThePoint.jl/previews/PR106/api#WhatsThePoint.KNNTopology"><code>KNNTopology</code></a> — k-nearest neighbor connectivity</p></li><li><p><a href="/WhatsThePoint.jl/previews/PR106/api#WhatsThePoint.RadiusTopology"><code>RadiusTopology</code></a> — All neighbors within a fixed radius</p></li></ul><p><strong>Local vs global indices:</strong> Topology on a <code>PointSurface</code> or <code>PointVolume</code> uses local indices (1 through <code>length(surf)</code>). Topology on a <code>PointCloud</code> uses global indices (1 through <code>length(cloud)</code>), where boundary points come first, followed by volume points.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Surface topology — local indices</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">surf </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> set_topology</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(surf, KNNTopology, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">neighbors</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(surf, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># indices into surf, e.g. [1, 4, 7, ...]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Cloud topology — global indices</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cloud </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> set_topology</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cloud, KNNTopology, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">neighbors</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cloud, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># indices into cloud, e.g. [1, 2, 5, 102, ...]</span></span></code></pre></div><p>Topology is computed <strong>eagerly</strong> when <code>set_topology</code> is called and is never automatically invalidated. Operations that move points (like <a href="/WhatsThePoint.jl/previews/PR106/api#WhatsThePoint.repel"><code>repel</code></a>) return objects with <a href="/WhatsThePoint.jl/previews/PR106/api#WhatsThePoint.NoTopology"><code>NoTopology</code></a> — call <code>set_topology</code> again after repulsion.</p><h2 id="Units" tabindex="-1">Units <a class="header-anchor" href="#Units" aria-label="Permalink to &quot;Units {#Units}&quot;">​</a></h2><p>WhatsThePoint integrates with <a href="https://github.com/PainterQubits/Unitful.jl" target="_blank" rel="noreferrer">Unitful.jl</a>. Physical units work directly throughout the API:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">spacing </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ConstantSpacing</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mm)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cloud </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> set_topology</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cloud, RadiusTopology, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mm)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">split_surface!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(boundary, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">75</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">°)</span></span></code></pre></div><p>Units propagate through all operations — point coordinates, normals, areas, and spacing values all carry their units consistently.</p><p>Units enter the pipeline at import: mesh files carry no unit metadata, so every file-loading entry point (<code>import_mesh</code>, <code>PointBoundary</code>, <code>import_surface</code>, <code>suggest_spacing</code>) requires the unit the file&#39;s raw numbers are meant in, and <em>reinterprets</em> them in that unit (a stored <code>46</code> becomes <code>46 mm</code> — no conversion).</p><h2 id="Parallelism" tabindex="-1">Parallelism <a class="header-anchor" href="#Parallelism" aria-label="Permalink to &quot;Parallelism {#Parallelism}&quot;">​</a></h2><p>WhatsThePoint uses <a href="https://github.com/JuliaFolds2/OhMyThreads.jl" target="_blank" rel="noreferrer">OhMyThreads.jl</a> for threaded execution. The following operations are parallelized:</p><ul><li><p>Normal computation and orientation (<code>compute_normals</code>, <code>orient_normals!</code>)</p></li><li><p>Point-in-volume testing (<code>isinside</code>)</p></li><li><p>Node repulsion (<code>repel</code>)</p></li><li><p>Octree queries and construction</p></li></ul><p>To use multiple threads, start Julia with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auto</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # use all available cores</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # use 8 threads</span></span></code></pre></div><p>No code changes are needed — parallel execution is automatic when threads are available.</p><h2 id="Euclidean-Assumption" tabindex="-1">Euclidean Assumption <a class="header-anchor" href="#Euclidean-Assumption" aria-label="Permalink to &quot;Euclidean Assumption {#Euclidean-Assumption}&quot;">​</a></h2><p>WhatsThePoint currently supports <strong>Euclidean manifolds only</strong> (<code>𝔼{2}</code> and <code>𝔼{3}</code>). Functions like <code>compute_normals</code>, <code>orient_normals!</code>, <code>discretize</code>, <code>repel</code>, and <code>isinside</code> have explicit Euclidean type constraints.</p><p>Any coordinate system (Cartesian, Cylindrical, Polar, etc.) is supported <em>on</em> a Euclidean manifold — the constraint is about geometric structure (flat space), not coordinate representation.</p><p>The type system is designed so that non-Euclidean geometries (spherical, hyperbolic) can be added in the future through new method dispatches with appropriate geodesic operations.</p>`,40)])])}const g=i(n,[["render",o]]);export{u as __pageData,g as default};
